$base = "$env:USERPROFILE\Desktop\AssetManagement"
$enc  = [System.Text.Encoding]::UTF8
Write-Host "Stage 6B views..." -ForegroundColor Cyan

# Index.cshtml
$p = "$base\AssetManagement.Web\Views\Reports\Index.cshtml"
$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes($p, $b)
Write-Host "  OK: Index.cshtml" -ForegroundColor Green

# Index.cshtml
$p = "$base\AssetManagement.Web\Views\Asset\Index.cshtml"
$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes($p, $b)
Write-Host "  OK: Index.cshtml" -ForegroundColor Green

# Fix print button in Details to show whenever there are requests
$dp = "$base\AssetManagement.Web\Views\Asset\Details.cshtml"
$c = [System.IO.File]::ReadAllText($dp, $enc)
$oldPrint = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
$newPrint = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
if ($c.Contains($oldPrint)) {
    $c = $c.Replace($oldPrint, $newPrint)
    [System.IO.File]::WriteAllText($dp, $c, $enc)
    Write-Host "  OK: Print button always visible in Details" -ForegroundColor Green
}

cd $base
dotnet build 2>&1 | Select-Object -Last 4
if ($LASTEXITCODE -eq 0) { Write-Host "Stage 6B done!" -ForegroundColor Green }